def prevPermOpt1(arr):
    n = len(arr)
    for i in range(n - 2, -1, -1):
        if arr[i] > arr[i+1]:
            best_j = i + 1
            for j in range(i + 1, n):
                if arr[j] < arr[i] and arr[j] > arr[best_j]:
                    best_j = j
            # find leftmost of the same largest value
            while best_j > i + 1 and arr[best_j-1] == arr[best_j]:
                best_j -= 1
            arr[i], arr[best_j] = arr[best_j], arr[i]
            return arr
    return arr

